import React, { useState, useEffect } from "react";
import { BrowserRouter as Router, Routes, Route, Link, Navigate } from "react-router-dom";
import axios from "axios";
import Chart from "chart.js/auto";

// ✅ Password Input with show/hide toggle
function PasswordInput({ value, onChange, placeholder }) {
  const [visible, setVisible] = useState(false);

  return (
    <div style={{ display: "flex", alignItems: "center" }}>
      <input
        type={visible ? "text" : "password"}
        value={value}
        onChange={onChange}
        placeholder={placeholder}
        required
      />
      <button
        type="button"
        onClick={() => setVisible(!visible)}
        style={{
          marginLeft: "5px",
          cursor: "pointer",
          background: "none",
          border: "1px solid #ccc",
          borderRadius: "4px",
          padding: "2px 5px",
        }}
      >
        {visible ? "🙈" : "👁️"}
      </button>
    </div>
  );
}

function App() {
  const [user, setUser] = useState(null);

  // check login status
  useEffect(() => {
    axios
      .get("http://localhost:5000/api/me", { withCredentials: true })
      .then((res) => setUser(res.data))
      .catch(() => setUser(null));
  }, []);

  return (
    <Router>
      <nav>
        <Link to="/">Home</Link>
        {user ? (
          <>
            <Link to="/dashboard">Dashboard</Link>
            <Link to="/profile">Profile</Link>
            <a
              href="#"
              onClick={() => {
                axios.post("http://localhost:5000/api/logout", {}, { withCredentials: true });
                setUser(null);
              }}
            >
              Logout
            </a>
          </>
        ) : (
          <>
            <Link to="/login">Login</Link>
            <Link to="/register">Register</Link>
          </>
        )}
      </nav>

      <Routes>
        <Route path="/" element={<h1>Welcome to Finance Logger</h1>} />
        <Route
          path="/login"
          element={user ? <Navigate to="/dashboard" /> : <Login setUser={setUser} />}
        />
        <Route
          path="/register"
          element={user ? <Navigate to="/dashboard" /> : <Register setUser={setUser} />}
        />
        <Route
          path="/dashboard"
          element={user ? <Dashboard /> : <Navigate to="/login" />}
        />
        <Route
          path="/profile"
          element={user ? <Profile user={user} /> : <Navigate to="/login" />}
        />
      </Routes>
    </Router>
  );
}

// ✅ LOGIN
function Login({ setUser }) {
  const [form, setForm] = useState({ email: "", password: "" });

  const submit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post("http://localhost:5000/api/login", form, {
        withCredentials: true,
      });
      setUser(res.data.user);
    } catch {
      alert("Login failed");
    }
  };

  return (
    <form onSubmit={submit}>
      <h2>Login</h2>
      <input
        type="email"
        placeholder="Email"
        value={form.email}
        onChange={(e) => setForm({ ...form, email: e.target.value })}
        required
      />
      <PasswordInput
        value={form.password}
        onChange={(e) => setForm({ ...form, password: e.target.value })}
        placeholder="Password"
      />
      <button type="submit">Login</button>
    </form>
  );
}

// ✅ REGISTER
function Register({ setUser }) {
  const [form, setForm] = useState({ username: "", email: "", password: "" });

  const submit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post("http://localhost:5000/api/register", form, {
        withCredentials: true,
      });
      setUser(res.data.user);
    } catch {
      alert("Registration failed");
    }
  };

  return (
    <form onSubmit={submit}>
      <h2>Register</h2>
      <input
        type="text"
        placeholder="Username"
        value={form.username}
        onChange={(e) => setForm({ ...form, username: e.target.value })}
        required
      />
      <input
        type="email"
        placeholder="Email"
        value={form.email}
        onChange={(e) => setForm({ ...form, email: e.target.value })}
        required
      />
      <PasswordInput
        value={form.password}
        onChange={(e) => setForm({ ...form, password: e.target.value })}
        placeholder="Password"
      />
      <button type="submit">Register</button>
    </form>
  );
}

// ✅ DASHBOARD
function Dashboard() {
  const [expenses, setExpenses] = useState([]);

  useEffect(() => {
    axios
      .get("http://localhost:5000/api/expense", { withCredentials: true })
      .then((res) => setExpenses(res.data))
      .catch(() => setExpenses([]));
  }, []);

  return (
    <div>
      <h2>Dashboard</h2>
      {expenses.map((e) => (
        <p key={e._id}>
          {e.description}: {e.amount}
        </p>
      ))}
    </div>
  );
}

// ✅ PROFILE
function Profile({ user }) {
  const [passwords, setPasswords] = useState({
    oldPassword: "",
    newPassword: "",
  });

  const changePassword = async (e) => {
    e.preventDefault();
    try {
      await axios.post(
        "http://localhost:5000/api/change-password",
        passwords,
        { withCredentials: true }
      );
      alert("Password changed");
    } catch {
      alert("Password change failed");
    }
  };

  return (
    <div>
      <h2>Profile</h2>
      <p>Username: {user.username}</p>
      <p>Email: {user.email}</p>

      <form onSubmit={changePassword}>
        <h3>Change Password</h3>
        <PasswordInput
          value={passwords.oldPassword}
          onChange={(e) =>
            setPasswords({ ...passwords, oldPassword: e.target.value })
          }
          placeholder="Old Password"
        />
        <PasswordInput
          value={passwords.newPassword}
          onChange={(e) =>
            setPasswords({ ...passwords, newPassword: e.target.value })
          }
          placeholder="New Password"
        />
        <button type="submit">Change</button>
      </form>
    </div>
  );
}

export default App;
